            {
                isConnected = false;
                roomData.SetLaser();
            }
            Vector3 laserBeamEnd = hit.point;
            laserBeam.SetPosition(0, transform.position);
            laserBeam.SetPosition(1, laserBeamEnd);
        }
    }
}

